    // (a hyphen followed by one or more letters) (?:-[a-z]+)*.
    // This pattern ensures that hyphens are always surrounded by letters 
    // and captures maximal contiguous sequences satisfying the rules.
    const wordRegex = /[a-z]+(?:-[a-z]+)*/g;

    const wordCounts = new Map();

    let match;
    // Use matchAll to iterate over all non-overlapping matches
    const matches = [...s.matchAll(wordRegex)];

    for (const match of matches) {
        const word = match[0];
        // Count the occurrence of each valid word
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    }

    // 3. Generate the result array for queries
    const ans = [];
    for (const query of queries) {
        const count = wordCounts.get(query) || 0;
        ans.push(count);
    }

    return ans;
}
