    // Step 1: Concatenate chunks
    const S = chunks.join('');
    const N = S.length;

    // Map to store frequency of each word found
    const wordCounts = new Map();

    let i = 0;
    while (i < N) {
        const char_i = S[i];

        if (isLetter(char_i)) {
            // Potential start of a word
            let W = "";
            let j = i;

